using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using ModelContextProtocol.Server;

namespace McpServer;

// The [McpServerToolType] attribute marks this class for automatic discovery
// by WithToolsFromAssembly(). The MCP SDK creates a NEW instance per tool
// invocation — constructor parameters are resolved from the DI container.
[McpServerToolType]
public class WeatherTools
{
    private readonly HttpClient _http;

    // The SDK resolves constructor args from DI each call. Because we
    // registered a named client "WeatherApi", we inject IHttpClientFactory
    // and create the client manually. (If you register a typed client
    // instead, you can inject HttpClient directly.)
    public WeatherTools(IHttpClientFactory httpClientFactory)
    {
        _http = httpClientFactory.CreateClient("WeatherApi");
    }

    // [McpServerTool] exposes this method as a tool. The LLM sees:
    //   Name:        "GetCurrentWeather"  (from method name)
    //   Description: from [Description]
    //   Parameters:  inferred from method params + their [Description]s
    [McpServerTool, Description("Get current weather for a location.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude of the location")]  double latitude,
        [Description("Longitude of the location")] double longitude)
    {
        var url = $"v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m";

        var forecast = await _http.GetFromJsonAsync<OpenMeteoResponse>(url);

        if (forecast?.Current is null)
            return "No weather data available.";

        return $"Temperature: {forecast.Current.Temperature2m}°C, "
             + $"Wind: {forecast.Current.WindSpeed10m} km/h";
    }

    // You can add more tools in the same class or in separate
    // [McpServerToolType] classes — they'll all be discovered.
    [McpServerTool, Description("Look up coordinates for a city name.")]
    public async Task<string> GeocodeCityName(
        [Description("City name to look up")] string city)
    {
        var url = $"https://geocoding-api.open-meteo.com/v1/search?name={Uri.EscapeDataString(city)}&count=1";
        var result = await _http.GetFromJsonAsync<GeocodeResponse>(url);

        if (result?.Results is not { Count: > 0 })
            return $"Could not find coordinates for '{city}'.";

        var loc = result.Results[0];
        return $"{loc.Name}: {loc.Latitude}, {loc.Longitude}";
    }
}

// --- DTOs for JSON deserialization ---

public record OpenMeteoResponse(
    [property: JsonPropertyName("current")] CurrentWeather? Current);

public record CurrentWeather(
    [property: JsonPropertyName("temperature_2m")]   double Temperature2m,
    [property: JsonPropertyName("wind_speed_10m")]   double WindSpeed10m);

public record GeocodeResponse(
    [property: JsonPropertyName("results")] List<GeoResult>? Results);

public record GeoResult(
    [property: JsonPropertyName("name")]      string Name,
    [property: JsonPropertyName("latitude")]  double Latitude,
    [property: JsonPropertyName("longitude")] double Longitude);

