var builder = Host.CreateApplicationBuilder(args);

// Register a named HttpClient for the weather API.
// IHttpClientFactory is the recommended way to manage HttpClient lifetimes —
// it handles pooling, DNS rotation, and avoids socket exhaustion.
builder.Services.AddHttpClient("WeatherApi", client =>
{
    client.BaseAddress = new Uri("https://api.open-meteo.com/");
    client.DefaultRequestHeaders.Add("Accept", "application/json");
});

// AddMcpServer registers the MCP pipeline and scans the assembly for
// classes decorated with [McpServerToolType]. Each public method marked
// [McpServerTool] becomes a callable tool. The server uses stdio transport
// so it can be launched as a child process by any MCP client.
builder.Services
    .AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();

await builder.Build().RunAsync();

